import React from 'react';
import './App.css';

function App() {
  const board = [];
  for (let row = 0; row < 8; row++) {
    for (let col = 0; col < 8; col++) {
      const isLight = (row + col) % 2 === 0;
      board.push(
        <div
          key={`${row}-${col}`}
          className={`square ${isLight ? 'light' : 'dark'}`}
        />
      );
    }
  }

  return <div className="board">{board}</div>;
}

export default App;
